                             N,
                             hidden_dim,
                             block,
                             rank,
                             dbuffer_list,
                             data_offset,
                             flag_color,
                             data_size_per_phase);
        block += grid;
        flag_color++;
    }
    if(threadIdx.x == 0 && threadIdx.y == 0)
        d_flag_color[blockIdx.x] = flag_color;
}

